import { ref, reactive, onMounted, nextTick } from 'vue'
import { ElMessage } from 'element-plus'
import { enumSelect, listCommon } from '@/util/vueutil/commonList.js'
import { request } from '@/util/globalContext'

export default function useHomeIndex(listRef) {
    const orderSearchForm = reactive({
        orderId: '',
        orderStatus: ''
    })

    const {
        oneShow,
        listShow,
        handleReset,
        handleSelectionChange,
        handleCurrentRowChange
    } = listCommon(orderSearchForm)

    const orderDialogVisible = ref(false)
    const orderDialogType = ref('view')
    const orderFormRef = ref(null)
    const orderItems = ref([])

    const ORDER_FORM_DEFAULT = {
        id: '',
        orderId: '',
        name: '',
        phone: '',
        areaNames: '',
        addressDetail: '',
        items: '',
        ygTotalWeight: '',
        ygTotalAmount: '',
        orderStatus: '',
        orderStatusName: '',
        remark: ''
    }
    const orderFormData = reactive({ ...ORDER_FORM_DEFAULT })

    const orderFormRules = reactive({
        orderStatus: [
            { required: true, message: '请选择订单状态', trigger: 'change' }
        ]
    })

    const Options = ref({
        wxOrderStatus: []
    });

    const handleLoadList = async (paginationParams) => {
        if (!listRef.value) return
        if (!listRef.value.isInited) {
            await nextTick()
            if (!listRef.value.isInited) {
                ElMessage.warning('列表组件初始化中，请稍后重试')
                return
            }
        }

        listRef.value.setLoading(true)

        try {
            const params = {
                ...paginationParams,
                ...orderSearchForm
            }
            const res = await request.post('/home/getOrderList', params)

            if (res.code === 200) {
                listRef.value.updateListData(res.data.records || [])
                listRef.value.updatePagination({
                    pageNum: paginationParams.pageNum,
                    pageSize: paginationParams.pageSize,
                    total: res.data.total || 0
                })
            } else {
                ElMessage.error('列表加载失败：' + (res.msg || '接口异常'))
                listRef.value.updateListData([])
                listRef.value.updatePagination({ ...paginationParams, total: 0 })
            }
        } catch (error) {
            ElMessage.error('列表加载失败：网络异常')
            listRef.value.updateListData([])
            listRef.value.updatePagination({ ...paginationParams, total: 0 })
        } finally {
            listRef.value.setLoading(false)
        }
    }

    const getOrderDetail = async (id) => {
        try {
            const res = await request.get('/home/getOrderDetail', { params: { id } })
            if (res.code === 200) {
                const order = res.data.order || {}
                orderFormData.id = order.id
                orderFormData.orderId = order.orderId
                orderFormData.name = order.name
                orderFormData.phone = order.phone
                orderFormData.areaNames = order.areaNames
                orderFormData.addressDetail = order.addressDetail
                orderFormData.items = order.items
                orderFormData.ygTotalWeight = order.ygTotalWeight
                orderFormData.ygTotalAmount = order.ygTotalAmount
                orderFormData.orderStatus = order.orderStatus
                orderFormData.orderStatusName = order.orderStatusName
                orderFormData.remark = order.remark

                orderItems.value = res.data.items || []
            } else {
                ElMessage.error(res.msg || '获取订单详情失败')
            }
        } catch (error) {
            ElMessage.error('获取订单详情失败：网络异常')
        }
    }

    const handleViewOrder = async (row) => {
        orderDialogType.value = 'view'
        await getOrderDetail(row.id)
        orderDialogVisible.value = true
    }

    const handleEditOrder = async (row) => {
        orderDialogType.value = 'edit'
        await getOrderDetail(row.id)
        orderDialogVisible.value = true
    }

    const handleSubmitOrder = async () => {
        if (!orderFormRef.value) return

        const isValid = await new Promise((resolve) => {
            orderFormRef.value.validate((valid) => {
                resolve(valid);
            });
        });
        if (!isValid) return;

        try {
            const params = {
                id: orderFormData.id,
                orderStatus: orderFormData.orderStatus,
                remark: orderFormData.remark
            }
            const res = await request.post('/home/updateOrder', params)

            if (res.code === 200) {
                ElMessage.success('修改成功')
                orderDialogVisible.value = false
                const pagination = listRef.value.getPagination()
                handleLoadList(pagination)
            } else {
                ElMessage.error('修改失败：' + (res.msg || '接口异常'))
            }
        } catch (error) {
            ElMessage.error('修改失败：网络异常')
        }
    }

    const getStatusEnum = async () => {
        try {
            const res = await enumSelect('enumType', 'wx_order_status').catch(() => []);
            Options.value.wxOrderStatus = res;
        } catch (error) {
            console.log('初始化枚举失败:', error)
        }
    }

    onMounted(async () => {
        await nextTick();
        await getStatusEnum()

        setTimeout(() => {
            if (listRef.value?.isInited) {
                const pagination = listRef.value.getPagination()
                handleLoadList(pagination)
            }
        }, 50)
    })

    return {
        orderSearchForm,
        orderItems,
        oneShow,
        listShow,
        handleReset,
        handleSelectionChange,
        handleCurrentRowChange,
        handleLoadList,
        handleViewOrder,
        handleEditOrder,
        handleSubmitOrder,
        orderDialogVisible,
        orderDialogType,
        orderFormRef,
        orderFormData,
        orderFormRules,
        Options
    }
}
