<!--
        selection-type : 单选/复选/关闭 模式，具体：
                          - radio：单选模式（无复选框，通过行高亮标识选中行，点击行触发选中状态切换，同步触发current-row-change和selection-change事件）；
                          - checkbox：多选模式（显示复选框列，可勾选多行，点击行也可切换复选框状态，selection-change事件返回选中行数组）；
                          - none：无选择交互（隐藏选择相关逻辑，不触发任何选择事件）；
                          本场景选radio，适配角色列表「单条编辑/删除/配置菜单」的业务诉求。
        row-key ：表格行的唯一标识字段，底层绑定el-table的row-key属性，用于：
                  1. 行选择/高亮的唯一性判断（如radio模式匹配当前行、checkbox模式判断选中状态）；
                  2. Vue列表渲染的key优化，避免行渲染异常；
                  本场景指定为roleId，因角色数据的唯一标识为roleId（非默认id）。
        has-more-search : 是否显示搜索扩展区的展开/收起按钮，true显示、false隐藏；
                          本场景为true，因角色列表包含「固定搜索项（角色ID/名称/是否生效）+ 扩展搜索项（创建时间/更新时间）」，需支持扩展搜索。
        auto-load : 组件挂载后是否自动触发数据加载，true则onMounted时触发load-start事件，false需手动触发；
                    本场景为true，实现角色列表页面加载后默认展示数据。
        ref : 父组件获取CommonList组件实例的标识，用于调用组件暴露的方法（如updateListData更新表格数据、setLoading设置加载状态、updatePagination更新分页）；
              本场景为listRef，RoleList中通过该ref操作通用列表的核心状态/数据。
        cellOverflow : 表格单元格内容溢出处理方式，ellipsis为单行省略（默认）、wrap为换行展示；
                       本场景为ellipsis，保证角色列表单元格（如角色描述）单行展示，避免行高不一致。
        @selection-change : 选中项变更时触发的事件，参数为选中行数组（radio模式为[当前行]/[]，checkbox模式为选中行集合）；
                            本场景绑定handleSelectionChange，同步更新selectedRow变量，为编辑/删除按钮禁用状态提供依据。
        @current-row-change : 仅radio模式下触发，表格原生current-change事件（切换高亮行时）；
                              本场景绑定handleCurrentRowChange，作为selection-change的补充，强化单选行状态的准确性。
        @load-start : 组件初始化自动加载时触发的事件（auto-load为true时）；
                      本场景绑定handleLoadList，与查询/分页复用同一加载方法，实现初始化加载角色数据。
        @search-click : 点击「查询」按钮时触发的事件，触发前会重置页码为1；
                        本场景绑定handleLoadList，实现搜索条件变更后重新加载角色列表。
        @pagination-change : 分页参数变更时触发（切换页码/调整页大小），参数为最新分页信息；
                             本场景绑定handleLoadList，实现分页切换时加载对应页的角色数据。
        @reset-click : 点击「重置」按钮时触发的事件，触发前会重置页码为1；
                       本场景绑定handleReset，实现清空搜索表单并重新加载无筛选的角色列表。
-->

<!-- 通用列表公共组件：封装搜索区、表格、分页逻辑，支持单选/多选/无选择框，分页嵌入表格底部 -->
<template>
    <div class="common-list-container" ref="containerRef">
        <!-- 搜索区域：分为固定展示区+可展开/收起的扩展区 -->
        <div class="common-list-search-box">
            <div class="common-search-header">
                <!-- 搜索固定区：默认展示的搜索项 -->
                <div class="common-search-fixed">
                    <slot name="search-item-fixed"></slot>
                </div>
                <!-- 搜索操作按钮组：查询、重置、展开/收起 -->
                <div class="common-search-actions">
                    <el-button type="primary" @click="handleSearchClick">查询</el-button>
                    <el-button @click="handleResetClick">重置</el-button>
                    <el-button
                            v-if="hasMoreSearch"
                            type="text"
                            class="expand-btn"
                            @click="isSearchExpand = !isSearchExpand"
                            :class="{ 'rotate-icon': isSearchExpand }"
                    >
                        <i class="el-icon el-icon-arrow-down">
                            <el-icon size="20" color="#409eff">
                                <CaretTop/>
                            </el-icon>
                        </i>
                    </el-button>
                </div>
            </div>
            <!-- 搜索扩展区：需手动展开显示更多搜索项 -->
            <div
                    class="common-search-expand"
                    v-show="hasMoreSearch && isSearchExpand"
            >
                <slot name="search-item-expand"></slot>
            </div>
        </div>

        <!-- 操作按钮组插槽：自定义表格上方的功能按钮 -->
        <div class="common-list-btn-group">
            <slot name="btn-group"></slot>
        </div>

        <!-- 表格容器：移除高度计算，分页嵌入表格底部 -->
        <div class="common-list-table-wrapper">
            <el-table
                    class="common-list-table"
                    :data="innerTableData"
                    border
                    stripe
                    v-loading="innerLoading"
                    @selection-change="handleSelectionChange"
                    @current-change="handleCurrentRowChange"
                    @row-click="handleRowClick"
                    :row-key="rowKey"
                    ref="tableRef"
                    :show-overflow-tooltip="true"
                    :class="`cell-overflow-${cellOverflow}`"
                    :row-class-name="rowClassName"
                    :highlight-current-row="selectionType === 'radio'"
                    :select-on-indeterminate="false"
            >
                <!-- 表格空状态自定义：加载中/暂无数据 -->
                <template #empty>
                    <div class="table-empty-wrap">
                        <el-icon size="40" color="#ccc">
                            <Empty/>
                        </el-icon>
                        <p style="margin-top: 12px; font-size: 14px; color: #999;">{{ innerLoading ? '加载中...' : '暂无数据' }}</p>
                    </div>
                </template>

                <!-- 选择列控制：仅checkbox类型显示复选框列；radio靠原生高亮，none不显示选择列 -->
                <el-table-column
                        v-if="selectionType === 'checkbox'"
                        type="selection"
                        width="55"
                        align="center"
                ></el-table-column>

                <!-- 表格列插槽：自定义表格列配置 -->
                <slot name="table-column"></slot>

                <!-- 分页嵌入表格底部：仅表格有数据且非加载中时显示 -->
                <template #append>
                    <div
                            class="common-list-pagination"
                            v-if="innerTableData.length > 0 && !innerLoading"
                    >
                        <el-pagination
                                v-model:current-page="pagination.pageNum"
                                v-model:page-size="pagination.pageSize"
                                :page-sizes="[10, 20, 50, 100]"
                                :total="pagination.total"
                                layout="total, sizes, prev, pager, next, jumper"
                                @size-change="handleSizeChange"
                                @current-change="handleCurrentChange"
                        ></el-pagination>
                    </div>
                </template>
            </el-table>
        </div>

        <!-- 额外内容插槽：自定义组件底部内容 -->
        <slot name="extra"></slot>
    </div>
</template>

<script setup>
    import {
        defineEmits,
        defineExpose,
        defineProps,
        nextTick,
        onMounted,
        onUnmounted,
        reactive,
        ref,
        toRefs,
        watch
    } from 'vue'

    // Props定义：核心配置项
    const props = defineProps({
        // 选择类型：none(无选择交互)、radio(单选/高亮)、checkbox(多选/复选框)
        selectionType: {
            type: String,
            default: 'radio',
            validator: (val) => ['none', 'radio', 'checkbox'].includes(val)
        },
        // 表格行唯一标识字段，用于行选择/高亮判断
        rowKey: {
            type: String,
            default: 'id'
        },
        // 是否存在更多搜索项（控制展开/收起按钮显示）
        hasMoreSearch: {
            type: Boolean,
            default: false
        },
        // 初始分页配置：pageNum(当前页)、pageSize(页大小)、total(总条数)
        initialPagination: {
            type: Object,
            default: () => ({pageNum: 1, pageSize: 10, total: 0})
        },
        // 单元格内容溢出处理：ellipsis(单行省略)、wrap(换行展示)
        cellOverflow: {
            type: String,
            default: 'ellipsis',
            validator: (val) => ['ellipsis', 'wrap'].includes(val)
        },
        // 是否在组件挂载后自动触发数据加载
        autoLoad: {
            type: Boolean,
            default: true
        }
    })

    // 事件定义：向外暴露的事件
    const emit = defineEmits([
        'selection-change', // 选择项变更（单选/多选均触发）
        'current-row-change', // 单选当前行变更
        'search-click', // 点击查询按钮
        'reset-click', // 点击重置按钮
        'pagination-change', // 分页参数变更（页码/页大小）
        'load-start' // 组件初始化自动加载触发
    ])

    // 响应式数据解构：简化props访问
    const {
        selectionType, rowKey, hasMoreSearch, initialPagination: initialPaginationProp,
        autoLoad
    } = toRefs(props)

    // 分页参数：响应式存储，基于初始配置初始化
    const pagination = reactive({...initialPaginationProp.value})
    // 搜索扩展区展开状态
    const isSearchExpand = ref(false)
    // 表格实例引用：用于调用表格原生方法（如setCurrentRow、doLayout）
    const tableRef = ref(null)
    // 组件容器引用
    const containerRef = ref(null)
    // 内部加载状态：控制表格loading显示
    const innerLoading = ref(false)
    // 表格内部数据：父组件通过updateListData更新
    const innerTableData = ref([])
    // 初始化完成标识：标记组件挂载完成
    const isInited = ref(false)
    // 多选选中行集合：存储checkbox类型选中的行
    const selection = ref([])
    // 单选当前行：存储radio类型选中的行
    const currentRow = ref(null)

    // 对外暴露方法：父组件可调用更新数据/状态
    // 更新表格展示数据
    const updateListData = (data) => {
        innerTableData.value = data || []
    }

    // 更新分页参数（页码/页大小/总条数）
    const updatePagination = (pageInfo) => {
        pagination.pageNum = pageInfo.pageNum || 1
        pagination.pageSize = pageInfo.pageSize || 10
        pagination.total = pageInfo.total || 0
    }

    // 设置表格加载状态
    const setLoading = (status) => {
        innerLoading.value = status
    }

    // 事件处理方法
    // 点击查询按钮：重置页码为1，触发search-click事件
    const handleSearchClick = () => {
        pagination.pageNum = 1
        emit('search-click', {...pagination})
    }

    // 点击重置按钮：重置页码为1，触发reset-click事件
    const handleResetClick = () => {
        pagination.pageNum = 1
        emit('reset-click', {...pagination})
    }

    // 多选选中变更：更新选中集合，触发selection-change事件
    const handleSelectionChange = (val) => {
        selection.value = val
        emit('selection-change', val)
    }

    // 单选当前行变更：更新当前行，同步触发selection-change（保持交互统一）
    const handleCurrentRowChange = (val) => {
        currentRow.value = val
        emit('selection-change', val ? [val] : [])
        emit('current-row-change', val)
    }

    // 表格行点击处理：不同选择类型触发不同交互
    const handleRowClick = (row) => {
        if (selectionType.value === 'radio') {
            // 单选：设置表格原生高亮行
            tableRef.value.setCurrentRow(row)
        } else if (selectionType.value === 'checkbox') {
            // 多选：点击行切换选中状态（无需点击复选框）
            const table = tableRef.value
            const isSelected = selection.value.some(item => item[rowKey.value] === row[rowKey.value])
            table.toggleRowSelection(row, !isSelected)
        }
        // none类型：无交互处理
    }

    // 分页页大小变更：更新pageSize，触发pagination-change事件
    const handleSizeChange = (val) => {
        pagination.pageSize = val
        emit('pagination-change', {...pagination})
    }

    // 分页页码变更：更新pageNum，触发pagination-change事件
    const handleCurrentChange = (val) => {
        pagination.pageNum = val
        emit('pagination-change', {...pagination})
    }

    // 表格行类名自定义：控制选中行高亮样式
    const rowClassName = ({row}) => {
        const rowId = row[rowKey.value]
        // none类型：无样式
        if (selectionType.value === 'none') return ''

        // radio类型：当前行添加高亮类
        if (selectionType.value === 'radio') {
            return currentRow?.value?.[rowKey.value] === rowId ? 'common-row-selected' : ''
        }

        // checkbox类型：选中行添加高亮类
        if (selectionType.value === 'checkbox') {
            return selection.value.some(item => item[rowKey.value] === rowId) ? 'common-row-selected' : ''
        }

        return ''
    }

    // 生命周期：挂载完成
    onMounted(() => {
        nextTick(() => {
            isInited.value = true // 标记初始化完成
            if (autoLoad.value) {
                emit('load-start', {...pagination}) // 自动触发加载
            }
        })
    })

    onUnmounted(() => {
        // 无清理逻辑，保留空方法
    })

    // 监听搜索展开状态：展开/收起后刷新表格布局，避免表格渲染异常
    watch(isSearchExpand, () => {
        nextTick(() => {
            if (tableRef.value) tableRef.value.doLayout()
        })
    })

    // 暴露给父组件的属性/方法
    defineExpose({
        isInited, // 初始化状态标识
        updateListData, // 更新表格数据
        updatePagination, // 更新分页信息
        setLoading, // 设置加载状态
        getPagination: () => ({...pagination}) // 获取当前分页参数（返回新对象避免响应式污染）
    })
</script>

<style scoped>
