    .common-list-container {
        padding: 24px;
        background: #fff;
        border-radius: 8px;
        box-shadow: 0 2px 12px 0 rgba(0, 0, 0, 0.04);
        min-height: calc(100vh - 48px);
        display: flex;
        flex-direction: column;
        gap: 20px;
    }

    /* 搜索区样式：背景、边框、布局 */
    .common-list-search-box {
        padding: 20px;
        border: 1px solid #e8e8e8;
        border-radius: 6px;
        flex-shrink: 0;
        display: flex;
        flex-direction: column;
        gap: 16px;
        background: #fafafa;
    }

    .common-search-header {
        display: flex;
        justify-content: space-between;
        align-items: flex-start;
        width: 100%;
        min-height: 48px;
    }

    /* 搜索固定区：flex布局，支持换行 */
    .common-search-fixed {
        display: flex;
        flex-wrap: wrap;
        align-items: flex-start;
        gap: 16px 24px;
        flex: 1;
        min-height: 48px;
    }

    /* 搜索扩展区：与固定区分割，顶部虚线边框 */
    .common-search-expand {
        display: flex;
        flex-wrap: wrap;
        align-items: center;
        gap: 16px 24px;
        padding-top: 12px;
        border-top: 1px dashed #e8e8e8;
        width: 100%;
    }

    /* 搜索操作按钮组：靠右，固定宽度不收缩 */
    .common-search-actions {
        display: flex;
        align-items: flex-start;
        gap: 12px;
        flex-shrink: 0;
