        gap: 12px;
    }

    /* 手机端搜索头部改为垂直排列 */
    .common-search-header {
        flex-direction: column;
        align-items: stretch;
        gap: 12px;
    }

    /* 手机端搜索固定区：搜索条件自动换行，名称和框在同一行 */
    .common-search-fixed {
        flex-direction: row;
        flex-wrap: wrap;
        gap: 12px 20px;
        width: 100%;
        justify-content: flex-start;
    }

    /* 搜索固定区只有一个条件时居中 */
    .common-search-fixed:has(.common-search-item:only-child) {
